ee:message.ee:set-payload:
%dw 2.0
//Set the input type expectation to XML and output to JSON
input payload application/xml
output application/json
---
{
	"importMetadata": {
		//Read XML Attributes using the .@ operator
		"orderReference": payload.order.@id,

		//Flattening nested child structures directly into simple strings
		"buyerCompany": payload.order.customer.company,
		"buyerContact": payload.order.customer.contactInfo.phone
	},

	//Map XML repetitions. 
	//DataWeave safely targets a repeating element list using .*
	"processedParts": payload.order.partsList.*part map (item) -> {
		"partSku": item.sku,
		"name": item.description,
		"category": item.@`type`, //Escaping 'type' because it's a DW reserved keyword
		"basePrice": item.cost as Number
	}
}
